// generar_216_peso_sincronizado.js
// CHIQUI Entre Señales — El peso alimenta la curva desde cualquier lugar
//
// Hoy solo el PesoTracker registraba en historial_peso. Ahora TODOS los
// lugares donde se ingresa un peso alimentan la curva de cambios:
//
// 1) components/ExamenesLab.tsx → al guardar un examen con "Peso ese
//    día", ese peso se registra en el historial CON LA FECHA DEL
//    EXAMEN. Si ya había un peso ese día, se actualiza (no duplica).
//    peso_actual de la mascota solo se actualiza si no existe un
//    registro de peso más reciente (un examen antiguo no pisa el peso
//    vigente).
// 2) app/perfil/page.tsx → al editar el peso en el perfil, el nuevo
//    valor entra al historial con la fecha de hoy. SOLO si el peso
//    cambió -- guardar el perfil sin tocar el peso no crea puntos.
// 3) app/mascota/nueva/page.tsx → el peso inicial queda como el primer
//    punto de la curva desde el día uno.
//
// No hay SQL.
//
// Uso: arrastrar este archivo a la raíz del proyecto y correr:
//   node generar_216_peso_sincronizado.js
//
// IMPORTANTE tras correr: revisa "git status" y confirma que
// app/perfil/page.tsx y app/mascota/nueva/page.tsx aparecen como
// MODIFICADOS (modified), no como archivos nuevos (untracked). Si
// alguno aparece como nuevo, NO hagas push y avísale a Dante el nombre
// real de esa carpeta.

const fs2 = require('fs')
const path = require('path')

const archivos = [
  {
    ruta: "components/ExamenesLab.tsx",
    base64: ""
  },
  {
    ruta: "app/perfil/page.tsx",
    base64: ""
  },
  {
    ruta: "app/mascota/nueva/page.tsx",
    base64: ""
  },
]

let errores = 0
for (const a of archivos) {
  try {
    const rutaCompleta = path.join(process.cwd(), a.ruta)
    fs2.mkdirSync(path.dirname(rutaCompleta), { recursive: true })
    const contenido = Buffer.from(a.base64, 'base64').toString('utf8')
    fs2.writeFileSync(rutaCompleta, contenido, 'utf8')
    console.log('OK: ' + a.ruta)
  } catch (e) {
    errores++
    console.error('ERROR escribiendo ' + a.ruta + ': ' + e.message)
  }
}

if (errores === 0) {
  console.log('')
  console.log('Listo. 3 archivos escritos correctamente.')
  console.log('Revisa git status (los 3 deben salir como modified) y luego git add / commit / push.')
} else {
  console.error('')
  console.error('Terminó con ' + errores + ' error(es). NO hagas git push todavía.')
  process.exit(1)
}
